#include <stdio.h>
#include <string.h>
#include <stdlib.h>

// expand around centre [left, right] and return the palindrome as a newly allocated string
char* expand(const char *s, int left, int right) {
    int n = strlen(s);
    while (left >= 0 && right < n && s[left] == s[right]) {
        left--;
        right++;
    }
    int len = right - left - 1;
    char *res = (char*)malloc(len + 1);
    memcpy(res, s + left + 1, len);
    res[len] = '\0';
    return res;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    char buffer[1005];
    for (int tc = 0; tc < T; ++tc) {
        if (!fgets(buffer, sizeof(buffer), stdin)) break;
        buffer[strcspn(buffer, "\n")] = '\0'; // remove trailing newline
        int n = strlen(buffer);
        char *best = (char*)malloc(1);
        best[0] = '\0';
        size_t bestLen = 0;
        for (int i = 0; i < n; ++i) {
            char *odd = expand(buffer, i, i);
            size_t lenOdd = strlen(odd);
            if (lenOdd > bestLen) {
                free(best);
                best = odd;
                bestLen = lenOdd;
            } else {
                free(odd);
            }
            char *even = expand(buffer, i, i + 1);
            size_t lenEven = strlen(even);
            if (lenEven > bestLen) {
                free(best);
                best = even;
                bestLen = lenEven;
            } else {
                free(even);
            }
        }
        printf("%s\n", best);
        free(best);
    }
    return 0;
}

